var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"알비온 2호 봉쇄좌표에 도착하였습니다.","JPN":"アルビオン2号、封鎖座標に到着しました。","ENG":"Albion No. 2 has arrived at the sealing coordinates.","TWN":"阿爾比恩2號已到達封鎖座標。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"3호와 4호 5호까지 순차적으로 차원 도약할 겁니다.","JPN":"3号、4号、5号まで順次に次元跳躍します。","ENG":"No. 3, 4, and 5 will take turns in dimension jumping.","TWN":"3號，4號和5號，將依次進行次元躍遷。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좌표를 수신하자 마자, 즉시 편대를 꾸려 대응하였는데도 이렇게 늦어버리다니.","JPN":"座標を受信するやいなや部隊を編成して対応したのに、こんなに遅れてしまうだなんて。","ENG":"We gathered some ships as soon as we received the coordinates, and still we are late.","TWN":"一收到座標，就立即組織隊伍應對，但還是晚了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 이 좌표를 전달해준 요원은 이미…….","JPN":"おそらく、この座標を送信したエージェントは既に……","ENG":"Then the agent who sent the coordinates must've already...","TWN":"那麼傳達這個座標的特工已經……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"큭! 알비온 3호로부터 송신!","JPN":"くっ！　アルビオン3号からの送信です！","ENG":"Kgh! Message from Albion No. 3!","TWN":"咳！阿爾比恩3號發來了訊號！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"차원 도약 중에 거대 촉수에 의해 공격받고 있다고 합니다!","JPN":"次元跳躍中、巨大触手の攻撃を受けているとのことです！","ENG":"They are being attacked by giant tentacles in the middle of dimension-jumping!","TWN":"說是次元躍遷時受到了巨大觸手的攻擊！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"기관장님, 서두르셔야 합니다!","JPN":"機関長、お急ぎください！","ENG":"Chief, you have to hurry!","TWN":"機關長，我們得抓緊時間！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알고있어요.","JPN":"わかっていますわ。","ENG":"I'm aware.","TWN":"我知道。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금의 저는 망설이는 것조차 허락되지 않겠죠.","JPN":"今の私には、迷うことすら許されないでしょうね。","ENG":"I'm not allowed even a second of hesitation right now.","TWN":"現在的我連一秒鐘的猶豫時間都不允許。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"다들 정신 바짝 차리도록 해!","JPN":"皆、しっかりしろ！","ENG":"Look alive, everyone!","TWN":"大家要打起萬分精神！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이 세계는 어떤 일이 벌어져도 이상하지 않은 마경이다!","JPN":"今この世界は何が起きてもおかしくない魔境となっている！","ENG":"We are in a hellscape where anything can happen!","TWN":"這個煉獄一樣的世界，無論發生什麼事都不奇怪！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장 엘리자베스 팬드래건이 현장의 모든 기관원들에게 전파합니다.","JPN":"機関長エリザベス・ペンドラゴンが、現場の全機関員に伝えます。","ENG":"Chief Elizabeth Pendragon, alerting all Institution members out on the field.","TWN":"我是機關長，伊莉莎白·潘德拉貢，現場所有人員聽著。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"현시간부로 기관은 적성 개체를 마왕 가아그셰블라에 준하는 최고 위험 등급으로 판단.","JPN":"現時刻をもって、機関は敵性個体を魔王ガアグシェブラに準ずる最高位の危険レベルと判断。","ENG":"As of now, the Institution deems the hostile the highest level of danger, no less than that of the Demon Lord Gha'agsheblah.","TWN":"此刻開始，機關將敵人個體判定為相當於魔王加格舍夫拉的最高危險等級。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적성 개체가 현실로 부상하는 것을 저지하기 위해.","JPN":"敵性個体が現実へと浮上することを阻止するために。","ENG":"In order to stop the hostile from emerging in the Normalside...","TWN":"為阻止敵人個體對現世造成傷害，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"총력전 체제에 돌입합니다.","JPN":"総力戦体制に突入します。","ENG":"We are entering an all-out war.","TWN":"我們將動員所有人力，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이에 따라 현장의 모든 기관원들은 즉시 테크 레벨 4 이상의 장비를 휴대한 뒤.","JPN":"よって、現場の全機関員は直ちにテックレベル4以上の装備を携帯し、","ENG":"Accordingly, all Institution members are to immediately carry gear higher than Tech Level 4 and–","TWN":"請所有人員立刻攜帶技術等級4以上的裝備…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"하나가 되어주세요.","JPN":"一つになってください。","ENG":"Become one.","TWN":"合而為一。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"반복합니다. 현장의 모든 기관원은 즉시.","JPN":"繰り返します。現場の全機関員はただちに。","ENG":"I repeat. All Institution members out on the field are to–","TWN":"再重複一次，現場所有人員立刻…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_NULL","text":{"KOREA":"무의미한 저항을 멈추고 모두 저와 하나가 되는 거예요.","JPN":"無意味な抵抗をやめ、全員私と一つになるのです。","ENG":"Stop your pointless resistance and become one with me.","TWN":"停止無謂的抵抗，並和我合而為一。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"흐흐, 흐하하하하하하하하하하하하핫……!!","JPN":"ふふ、ふははははははははは……！！","ENG":"Hehe, hehahahahAHAHAHAHA...!!","TWN":"呵呵，哈哈哈哈哈哈哈哈哈……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};